### Image field with directory and publicPath

Source: https://github.com/thinkmill/keystatic/blob/main/keystatic/packages/keystatic/src/form/fields/image/index.tsx

Shows how image field uses directory and publicPath parameters. The directory is combined with the slug automatically during serialization, and publicPath is passed to getSrcPrefix() which appends slug to construct the final public path.

```typescript
export function image<IsRequired extends boolean | undefined>({
  label,
  directory,
  validation,
  description,
  publicPath,
  transformFilename,
}: {
  label: string;
  directory?: string;
  validation?: { isRequired?: IsRequired };
  description?: string;
  publicPath?: string;
  transformFilename?: (originalFilename: string) => string;
}): AssetFormField<...> {
  return {
    serialize(value, args) {
      if (value === null) {
        return { value: undefined, asset: undefined };
      }
      const filename = args.suggestedFilenamePrefix
        ? args.suggestedFilenamePrefix + '.' + value.extension
        : value.filename;
      return {
        value: `${getSrcPrefix(publicPath, args.slug)}${filename}`,
        asset: { filename, content: value.data },
      };
    },
    directory: directory ? fixPath(directory) : undefined,
  };
}
```

--------------------------------

### fields.image with directory and publicPath Configuration

Source: https://github.com/thinkmill/keystatic/blob/main/keystatic/dev-projects/next-app/keystatic.config.tsx

Demonstrates configuring fields.image with directory and publicPath options inside a fields.document. The directory specifies where images are stored, and publicPath is the public URL prefix for accessing them.

```typescript
content: fields.document({
  label: 'Content',
  formatting: { alignment: true },
  images: {
    directory: 'public/images/posts',
    publicPath: '/images/posts/',
    schema: {
      title: fields.text({ label: 'Title' }),
    },
  },
}),
```

--------------------------------

### Public path construction with slug

Source: https://github.com/thinkmill/keystatic/blob/main/keystatic/packages/keystatic/src/form/fields/image/getSrcPrefix.tsx

The getSrcPrefix function combines publicPath with the entry slug to construct the final public path. It automatically appends the slug as a path segment after the publicPath, creating per-entry asset folders.

```typescript
export function getSrcPrefix(
  publicPath: string | undefined,
  slug: string | undefined
) {
  return typeof publicPath === 'string'
    ? `${publicPath.replace(/\/*$/, '')}/${
        slug === undefined ? '' : slug + '/'
      }`
    : '';
}
```

--------------------------------

### Directory and slug combined during serialization

Source: https://github.com/thinkmill/keystatic/blob/main/keystatic/packages/keystatic/src/app/updating.tsx

When serializing entry files, if a directory (file.parent) is specified for an asset field, the slug value is automatically appended to create per-entry asset folders. The final path becomes `directory/slug/filename`.

```typescript
...extraFiles.map(file => ({
  path: `${
    file.parent
      ? args.slug
        ? `${file.parent}/${args.slug.value}`
        : file.parent
      : args.basePath
  }/${file.path}`,
  contents: file.contents,
}))
```

--------------------------------

### Define a document field

Source: https://github.com/thinkmill/keystatic/blob/main/_autodocs/api-reference/form-fields.md

Configures a rich text editor with specific formatting, layout, and component block options.

```typescript
function document(options: {
  label: string;
  description?: string;
  formatting?: {
    inlineMarks?: 'inherit' | 'all' | Array<Mark>;
    softBreaks?: boolean;
    lists?: boolean;
    headingLevels?: number[];
    alignment?: boolean;
    blockquotes?: boolean;
    code?: boolean;
  };
  dividers?: boolean;
  links?: boolean;
  images?: { directory?: string } | boolean;
  tables?: boolean;
  layouts?: number[][];
  componentBlocks?: Record<string, ComponentSchema>;
}): ContentFormField
```

```typescript
const content = fields.document({
  label: 'Content',
  formatting: {
    inlineMarks: ['bold', 'italic', 'code'],
    headingLevels: [1, 2, 3],
  },
  dividers: true,
  links: true,
  images: { directory: 'public/blog-images' },
  tables: true,
  layouts: [[1, 1], [2, 1, 1]],
});
```

